class Solution {
    public int numSub(String s) {
        int count = 0, mod = 1000000007, ones = 0, res = 0;
        for (char c : s.toCharArray()) {
            if (c == '1') {
                ones++;
                count += ones;
                res = (res + count % mod) % mod;
            } else {
                ones = 0;
                count = 0;
            }
        }
        return res;
    }
}
